    panel.querySelector('[data-image="bottomBannerLeft"]')?.addEventListener('change', ev=>fileToOptimizedDataURL(ev.target, data=>{site.home.bottomBannerLeft=data; saveSite(); const img=ev.target.closest('.form-field').querySelector('img'); if(img) img.src=data; const st=panel.querySelector('[data-upload-status="bottomBannerLeft"]'); if(st) st.textContent='왼쪽 사진이 저장되었습니다.';}, {maxW:1200,maxH:800,quality:.82}));
    panel.querySelector('[data-image="bottomBannerRight"]')?.addEventListener('change', ev=>fileToOptimizedDataURL(ev.target, data=>{site.home.bottomBannerRight=data; saveSite(); const img=ev.target.closest('.form-field').querySelector('img'); if(img) img.src=data; const st=panel.querySelector('[data-upload-status="bottomBannerRight"]'); if(st) st.textContent='오른쪽 사진이 저장되었습니다.';}, {maxW:1200,maxH:800,quality:.82}));
